changeSet.sql:
-- The instance-admin view spans workspaces, so neither workspace-leading index serves it.
CREATE INDEX ix_config_audit_event_occurred
    ON config_audit_event (occurred_at DESC, id DESC);

-- "What did this administrator change" is the first question of an access review.
CREATE INDEX ix_config_audit_event_actor
    ON config_audit_event (actor_account_id, occurred_at DESC)
    WHERE actor_account_id IS NOT NULL;

-- changed_keys is persisted rather than derived precisely so it can be filtered on.
CREATE INDEX ix_config_audit_event_changed_keys
    ON config_audit_event USING GIN (changed_keys);

rollback.sql:
DROP INDEX IF EXISTS ix_config_audit_event_occurred;
DROP INDEX IF EXISTS ix_config_audit_event_actor;
DROP INDEX IF EXISTS ix_config_audit_event_changed_keys;
